fn solve(code: Vec<String>, businessLine: Vec<String>, isActive: Vec<bool>) -> Vec<String> {
    fn is_valid_code(s: &str) -> bool {
        if s.is_empty() {
            return false;
        }
        s.chars().all(|c| c.is_ascii_alphanumeric() || c == '_')
    }

    fn business_priority(business: &str) -> Option<usize> {
        match business {
            "electronics" => Some(0),
            "grocery" => Some(1),
            "pharmacy" => Some(2),
            "restaurant" => Some(3),
            _ => None
        }
    }

    let mut valid_coupons = Vec::new();

    for i in 0..code.len() {
        if !isActive[i] {
            continue;
        }
        if !is_valid_code(&code[i]) {
            continue;
        }
        if let Some(priority) = business_priority(&businessLine[i]) {
            valid_coupons.push((priority, code[i].clone()));
        }
    }

    valid_coupons.sort_by(|a, b| {
        a.0.cmp(&b.0).then_with(|| a.1.cmp(&b.1))
    });

    valid_coupons.into_iter().map(|(_, code)| code).collect()
}
```

